resource "aws_s3_bucket_lifecycle_configuration" "warm_to_cold" {
  bucket = aws_s3_bucket.trace_warm.id

  rule {
    id     = "warm-to-glacier"
    status = "Enabled"

    filter { prefix = "" }

    transition {
      days          = 61   # 30 HOT + 61 WARM = day 91
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      # day 7*365+1 = 2557; subtract the 91 days already elapsed
      days = 2466
    }
  }
}

resource "aws_s3_bucket_object_lock_configuration" "warm_lock" {
  bucket = aws_s3_bucket.trace_warm.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 2557   # 7 years from original ingest
    }
  }
}
